/**
 * SdV15 — raw ground-truth data recovered from the original release build
 * (cannon_game_v15, noAds.swf). Auto-generated from
 * design/original-data/release-v15/. Original 640x480 coords; id scheme 1-84
 * (see unit-table.md). Spawn tuple: [t sec, id, y, a (attack-x, 0=fly-through),
 * tip (behaviour variant), dop (extra)]. This is the source of truth the port
 * maps onto the remaster's prefabs/units — do not hand-edit; regenerate instead.
 */

export type V15Category = 'air' | 'compound' | 'ground' | 'npc' | 'boss';

export interface V15Unit {
  /** Original AS3 class (airframe art), e.g. 'Avalon1_1'. */
  cls: string;
  cat: V15Category;
  hp: number;
  speed: number;
  /** Contact/weapon damage. */
  dmg: number;
  score: number;
}

